function ZeroPadding(strString,nMaxNumber){while(strString.length<nMaxNumber){strString="0"+strString;}
return strString;}
function GetTodayData(){const kToday=new Date();const kData={nYear:kToday.getFullYear(),nMonth:kToday.getMonth()+1,nDate:kToday.getDate(),}
return kData;}
function YearCheck(strYear,kInfoItem=null,strErrorText=""){reNum=/^[0-9]*$/g;if(!reNum.test(strYear)){if(kInfoItem!=null){$(kInfoItem).text(strErrorText);$(kInfoItem).css({"color":"red"});}
return false;}
if(strYear.length!=4){if(kInfoItem!=null){$(kInfoItem).text(strErrorText);$(kInfoItem).css({"color":"red"});}
return false;}
return true;}
function MonthCheck(strMonth,kInfoItem=null,strErrorText=""){const nMonth=parseInt(strMonth);if(nMonth<=12&&nMonth>=1){return true;}
if(kInfoItem!=null){$(kInfoItem).text(strErrorText);$(kInfoItem).css({"color":"red"});}
return false;}
function Year2RocYear(nYear){return nYear-1911;}
function IsNumber(strString){if(strString==""){return false;}
return!isNaN(strString)}
function IsPositiveInteger(strString){reNum=/^[0-9]*$/g;if(!reNum.test(strString)){return false;}
return true;}
function IsEnglish(strString){var regExp=/^[a-zA-Z]*$/g;if(!regExp.test(strString)){return false;}
return true;}
function validateEmail(email)
{var re=/^(([^<>()[\]\\.,;:\s@\"]+(\.[^<>()[\]\\.,;:\s@\"]+)*)|(\".+\"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;return re.test(email);}
function RemoveArrayElement(kArray,kRemoveElement){let nIndex=kArray.indexOf(kRemoveElement);if(nIndex>-1){kArray.splice(nIndex,1);}
return kArray;}
function RemoveArrayElementByIndex(kArray,nIndex){if(nIndex<kArray.length){kArray.splice(nIndex,1);}
return kArray;}
function Object2Array(kObj){return Object.entries(kObj);}
function getRandomInteger(min,max){return Math.floor(Math.random()*(max-min+1))+min;}
function ArrayAddArray(kArray_1,kArray_2){return kArray_1.concat(kArray_2);}
function CloneArray(kSorceArray){let kCloneArray=kSorceArray.concat();return kCloneArray;}
function CloneObject(kSorceObject){return Object.assign({},kSorceObject);}
function SortMapByKey(kMap){return new Map([...kMap.entries()].sort());}
function RoundDecimal(fVal,nPrecision){return Math.round(Math.round(fVal*Math.pow(10,(nPrecision||0)+1))/10)/Math.pow(10,(nPrecision||0));}
function Assert(bState,strInfo="錯誤警告"){if(bState){return;}
alert(strInfo);}
function ShowInfo(strInfo){alert(strInfo);}
function GetUrl(){return window.location.pathname;}
function GetUrlInfo(kMap){var strUrl=location.search;if(strUrl.indexOf("?")!=-1){var getSearch=strUrl.split("?");const getPara=getSearch[1].split("&");for(i=0;i<getPara.length;i++){const kParaVal=getPara[i].split("=");kMap.set(kParaVal[0],kParaVal[1]);}}}
function GetBrowserViewportDimensions(){const nVw=Math.max(document.documentElement.clientWidth||0,window.innerWidth||0);const nVh=Math.max(document.documentElement.clientHeight||0,window.innerHeight||0);const kData={nVw:nVw,nVh:nVh}
return kData;}
function sleep(time){return new Promise((resolve)=>setTimeout(resolve,time));}
function IsWebPageBottom(){if((window.innerHeight+window.scrollY+10)>=document.body.offsetHeight){return true;}
return false;}
function SortMapByKey2(kMap){const kKeyArray=[];const iterator1=kMap.keys();for(let i=0;i<kMap.size;i++){const nKey=iterator1.next().value;kKeyArray.push(nKey);if(i==0){Assert(IsNumber(nKey),"Error : 排序 Key 必須是數字");}}
kKeyArray.sort(function(a,b){return a-b;});const kSortedMap=new Map;for(let i=0;i<kKeyArray.length;i++){const nKey=kKeyArray[i];const kValue=kMap.get(nKey);kSortedMap.set(nKey,kValue);}
return kSortedMap;}